(function(){

  var pct=0,el=document.getElementById('lpct'),bar=document.getElementById('lbar'),loader=document.getElementById('loader');

  var phases=['BOOTING CORE...','LOADING ASSETS...','RENDERING SPACE...','LAUNCHING PORTFOLIO...'];

  var status=loader.querySelector('.load-status');

  var interval=setInterval(function(){

    pct+=Math.random()*3+1;

    if(pct>100)pct=100;

    el.textContent=Math.floor(pct)+'%';

    bar.style.width=pct+'%';

    var phase=Math.floor(pct/25);

    if(phases[phase])status.textContent='● '+phases[phase];

    if(pct>=100){

      clearInterval(interval);

      status.textContent='● SYSTEM READY';

      setTimeout(function(){loader.classList.add('hide');setTimeout(function(){loader.style.display='none';},700);},400);

    }

  },28);

})();





// ===== EMBED PHOTO =====

document.getElementById('myPhoto').src = 'data:image/png;base64,';

// ===== GALAXY + SOLAR SYSTEM CANVAS =====

const cv = document.getElementById('bg');

const cx = cv.getContext('2d');

cv.width = window.innerWidth; cv.height = window.innerHeight;

// Stars

const stars = Array.from({length:300},()=>({

  x:Math.random()*cv.width, y:Math.random()*cv.height,

  r:Math.random()*1.6+.2, tw:Math.random()*Math.PI*2,

  sp:Math.random()*.04+.01,

  col:['#e8f4ff','#00f5ff','#8b00ff','#ffd700'][Math.floor(Math.random()*4)]

}));

// Nebulae

const nebulae = Array.from({length:6},()=>({

  x:Math.random()*cv.width, y:Math.random()*cv.height,

  r:Math.random()*180+80,

  col:Math.random()>.5?'rgba(139,0,255,.05)':'rgba(0,245,255,.04)',

  dx:(Math.random()-.5)*.08, dy:(Math.random()-.5)*.08

}));

// Solar system objects

const sun = {x:cv.width*.72, y:cv.height*.38, r:28};

const planets = [

  {dist:70, r:7, speed:.012, angle:0, col:'#6ab0ff', glow:'#6ab0ff'},       // Mercury

  {dist:110, r:10, speed:.008, angle:1, col:'#ffb347', glow:'#ffb347'},      // Venus

  {dist:155, r:12, speed:.005, angle:2.5, col:'#4daaff', glow:'#00f5ff',    // Earth

   moon:{dist:22, r:4, speed:.04, angle:0, col:'#aac8ff'}},

  {dist:200, r:9, speed:.003, angle:.8, col:'#ff6b4a', glow:'#ff6b4a'},      // Mars

  {dist:270, r:20, speed:.0015, angle:1.8, col:'#ffd580', glow:'#ffd700',    // Jupiter

   bands:true},

  {dist:340, r:16, speed:.001, angle:.5, col:'#e8c87a', glow:'#ffd700',      // Saturn

   rings:true},

];

let t = 0;

function drawGalaxy(){

  cx.clearRect(0,0,cv.width,cv.height);

  // Nebulae

  nebulae.forEach(n=>{

    n.x+=n.dx; n.y+=n.dy;

    if(n.x<-n.r)n.x=cv.width+n.r; if(n.x>cv.width+n.r)n.x=-n.r;

    if(n.y<-n.r)n.y=cv.height+n.r; if(n.y>cv.height+n.r)n.y=-n.r;

    const g=cx.createRadialGradient(n.x,n.y,0,n.x,n.y,n.r);

    g.addColorStop(0,n.col); g.addColorStop(1,'transparent');

    cx.fillStyle=g; cx.beginPath(); cx.arc(n.x,n.y,n.r,0,Math.PI*2); cx.fill();

  });

  // Stars

  stars.forEach(s=>{

    s.tw+=s.sp;

    const b=.3+.7*Math.abs(Math.sin(s.tw));

    cx.globalAlpha=b; cx.fillStyle=s.col;

    cx.shadowColor=s.col; cx.shadowBlur=s.r*3;

    cx.beginPath(); cx.arc(s.x,s.y,s.r*b,0,Math.PI*2); cx.fill();

    cx.shadowBlur=0;

  });

  cx.globalAlpha=1;

  // Orbit rings

  planets.forEach(p=>{

    cx.beginPath(); cx.arc(sun.x,sun.y,p.dist,0,Math.PI*2);

    cx.strokeStyle='rgba(255,255,255,.04)'; cx.lineWidth=1; cx.stroke();

  });

  // Sun glow

  const sg=cx.createRadialGradient(sun.x,sun.y,0,sun.x,sun.y,sun.r*4);

  sg.addColorStop(0,'rgba(255,200,50,.6)'); sg.addColorStop(.4,'rgba(255,120,0,.15)'); sg.addColorStop(1,'transparent');

  cx.fillStyle=sg; cx.beginPath(); cx.arc(sun.x,sun.y,sun.r*4,0,Math.PI*2); cx.fill();

  // Sun core

  const sc=cx.createRadialGradient(sun.x,sun.y-3,2,sun.x,sun.y,sun.r);

  sc.addColorStop(0,'#fff9e6'); sc.addColorStop(.5,'#ffd700'); sc.addColorStop(1,'#ff8800');

  cx.fillStyle=sc; cx.shadowColor='#ffd700'; cx.shadowBlur=30;

  cx.beginPath(); cx.arc(sun.x,sun.y,sun.r,0,Math.PI*2); cx.fill();

  cx.shadowBlur=0;

  // Planets

  planets.forEach(p=>{

    p.angle+=p.speed;

    const px=sun.x+Math.cos(p.angle)*p.dist;

    const py=sun.y+Math.sin(p.angle)*p.dist;

    // Saturn rings

    if(p.rings){

      cx.save();

      cx.translate(px,py); cx.scale(1,.35);

      cx.beginPath(); cx.arc(0,0,p.r+14,0,Math.PI*2);

      cx.strokeStyle='rgba(232,200,122,.5)'; cx.lineWidth=5; cx.stroke();

      cx.beginPath(); cx.arc(0,0,p.r+22,0,Math.PI*2);

      cx.strokeStyle='rgba(232,200,122,.25)'; cx.lineWidth=3; cx.stroke();

      cx.restore();

    }

    // Planet glow

    const pg=cx.createRadialGradient(px,py,0,px,py,p.r*2.5);

    pg.addColorStop(0,p.glow+'44'); pg.addColorStop(1,'transparent');

    cx.fillStyle=pg; cx.beginPath(); cx.arc(px,py,p.r*2.5,0,Math.PI*2); cx.fill();

    // Planet body

    const pb=cx.createRadialGradient(px-p.r*.3,py-p.r*.3,p.r*.1,px,py,p.r);

    pb.addColorStop(0,'#fff'); pb.addColorStop(.3,p.col); pb.addColorStop(1,'rgba(0,0,0,.5)');

    cx.fillStyle=pb; cx.shadowColor=p.glow; cx.shadowBlur=12;

    cx.beginPath(); cx.arc(px,py,p.r,0,Math.PI*2); cx.fill();

    cx.shadowBlur=0;

    // Jupiter bands

    if(p.bands){

      cx.save(); cx.beginPath(); cx.arc(px,py,p.r,0,Math.PI*2); cx.clip();

      cx.fillStyle='rgba(200,150,80,.3)';

      cx.fillRect(px-p.r,py-p.r*.3,p.r*2,p.r*.25);

      cx.fillRect(px-p.r,py+p.r*.1,p.r*2,p.r*.2);

      cx.restore();

    }

    // Moon

    if(p.moon){

      const m=p.moon; m.angle+=m.speed;

      const mx=px+Math.cos(m.angle)*m.dist;

      const my=py+Math.sin(m.angle)*m.dist;

      cx.fillStyle=m.col; cx.beginPath(); cx.arc(mx,my,m.r,0,Math.PI*2); cx.fill();

    }

  });

  // Shooting star occasionally

  if(Math.random()<.003){

    const sx=Math.random()*cv.width, sy=Math.random()*cv.height*.5;

    const grad=cx.createLinearGradient(sx,sy,sx+80,sy+40);

    grad.addColorStop(0,'rgba(255,255,255,0)'); grad.addColorStop(.5,'rgba(255,255,255,.8)'); grad.addColorStop(1,'rgba(255,255,255,0)');

    cx.strokeStyle=grad; cx.lineWidth=1.5;

    cx.beginPath(); cx.moveTo(sx,sy); cx.lineTo(sx+80,sy+40); cx.stroke();

  }

  t++; requestAnimationFrame(drawGalaxy);

}

drawGalaxy();

window.addEventListener('resize',()=>{cv.width=window.innerWidth;cv.height=window.innerHeight;sun.x=cv.width*.72;sun.y=cv.height*.38;});

// CURSOR

const cur=document.getElementById('cur'),crng=document.getElementById('crng');

let mx=0,my=0,rx=0,ry=0;

document.addEventListener('mousemove',e=>{mx=e.clientX;my=e.clientY;cur.style.left=mx+'px';cur.style.top=my+'px';});

(function animRing(){rx+=(mx-rx)*.12;ry+=(my-ry)*.12;crng.style.left=rx+'px';crng.style.top=ry+'px';requestAnimationFrame(animRing);})();

// BLAST RIPPLE

const rw=document.getElementById('rw');

document.addEventListener('click',e=>{

  [0,1,2].forEach(i=>setTimeout(()=>{

    const r=document.createElement('div');r.className='rip';

    const sz=60+i*50;

    r.style.cssText=`left:${e.clientX}px;top:${e.clientY}px;width:${sz}px;height:${sz}px;opacity:${.9-i*.25};border-color:${['rgba(0,245,255,.8)','rgba(0,102,255,.5)','rgba(139,0,255,.35)'][i]}`;

    rw.appendChild(r);setTimeout(()=>r.remove(),950);

  },i*75));

});

// REVEAL

const obs=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting)e.target.classList.add('visible');}),{threshold:.1});

document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));

// SKILL BARS

const bObs=new IntersectionObserver(es=>es.forEach(e=>{

  if(e.isIntersecting){const b=e.target.querySelector('.sk-bar');if(b&&!b.done){b.done=true;setTimeout(()=>b.style.width=b.dataset.w+'%',200);}}

}),{threshold:.3});

document.querySelectorAll('.skill-card').forEach(c=>bObs.observe(c));